import{_ as t,o as a,c as n,e as i}from"./app-cb4a12e2.js";const l={};function r(o,e){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="ai-agent-智能体" tabindex="-1"><a class="header-anchor" href="#ai-agent-智能体" aria-hidden="true">#</a> AI Agent 智能体</h1><h2 id="_1-什么是-ai-agent" tabindex="-1"><a class="header-anchor" href="#_1-什么是-ai-agent" aria-hidden="true">#</a> 1. 什么是 AI Agent？</h2><p>在行业中，&quot;Agent&quot; 的定义存在诸多差异：</p><ul><li>有人将其定义为可长期独立运行、通过各类工具完成复杂任务的完全自治系统；</li><li>也有人用它描述遵循预定义工作流的指令式系统。</li></ul><p>将上述所有变体统称为智能体系统（agentic systems），并对其中两个核心概念做了关键的架构区分：</p><ul><li><strong>工作流（Workflows）</strong>：通过预定义的代码路径，对大语言模型和工具进行编排的系统，执行路径是固定的、可预判的。</li><li><strong>Agent（智能体）</strong>：由大语言模型动态自主地主导执行流程与工具使用，全程自主掌控任务的完成方式，执行路径是非固定的、动态决策的。</li></ul><p>成功的 Agent 落地项目，普遍采用简单、可组合的模式，而非复杂的框架与黑盒封装。</p><h2 id="_2-何时使用智能体" tabindex="-1"><a class="header-anchor" href="#_2-何时使用智能体" aria-hidden="true">#</a> 2. 何时使用智能体</h2><p>智能体系统往往会用延迟和成本换取更优的任务表现，你需要先判断这笔交易是否值得：</p><ol><li>无需智能体的场景：对于绝大多数场景，通过检索增强、上下文示例优化单轮 LLM 调用，就足以满足需求。</li><li>优先选择工作流的场景：对于边界清晰、定义明确的任务，工作流能提供可预测性与一致性，是更优选择。</li><li>适合使用 Agent 的场景：当任务需要大规模的灵活性、模型驱动的动态决策，且无法通过固定路径硬编码实现时，Agent 才是最佳选择。</li></ol>',10)])])}const d=t(l,[["render",r],["__file","AI-Agent.html.vue"]]);export{d as default};
